glsl_code.rings:
out vec4 fragColor;
void main(){
    vec2 uv = vUV.st;
    vec2 p = (uv - 0.5) * vec2(1.777, 1.0) * 2.0;
    float radius = length(p);
    float angle = atan(p.y, p.x);
    float amp = abs(texture(sTD2DInputs[0], vec2(fract(radius * 0.35), 0.5)).r);
    float ringPhase = fract(radius * 9.0 - amp * 2.5);
    float ring = 1.0 - smoothstep(0.035, 0.09, abs(ringPhase - 0.5));
    float droplets = smoothstep(0.96, 1.0, sin(angle * 18.0 + amp * 12.0) * 0.5 + 0.5);
    float core = smoothstep(0.55 + amp * 0.25, 0.0, radius);
    vec3 ink = vec3(0.025, 0.015, 0.045);
    vec3 cyan = vec3(0.10, 0.92, 1.0);
    vec3 magenta = vec3(1.0, 0.15, 0.55);
    vec3 col = ink + cyan * ring * (0.45 + amp * 1.8);
    col += magenta * droplets * ring * (0.2 + amp * 1.4);
    col += vec3(1.0, 0.75, 0.35) * core * (0.3 + amp);
    fragColor = TDOutputSwizzle(vec4(col, 1.0));
}
